loadWWPContext.Call(&Context) If &Context.PesCod = 0 Return EndIf RetornaConfSistema.Call(&Context.EmpCod, &Context.FilCod, domConfSistema.TCon077_ExibeStatusDebitoCliente, &TCon077_ExibeStatusDebitoCliente) &PesRaz = &Context.PesRaz For Each Order EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &FilFan = FilFan Exit EndFor
if not &CreFrpPgtoCod.IsEmpty() getConfigFormaPagamentoReceber.call(&EmpCod, &FilCod, &Context.PesCod, &CreFrpPgtoCod, &CreFrpPgtoTip, &FrpPgtoDest, &sdtFormaPagamentoContas, &sdtFormaPagamentoLocalCobranca, &sdtFormaPagamentoBandeira) Endif
If &CreRecPag = ReceberPagar.Pagar &titulo = 'DUPLICATAS A PAGAR ' Else &titulo = 'DUPLICATAS A RECEBER ' Endif
Do Case case &CreFrpPgtoTip = TipoDuplicata.CARTAOC &titulo += 'TIPO CARTÃO CRÉDITO' case &CreFrpPgtoTip = TipoDuplicata.CARTAOD &titulo += 'TIPO CARTÃO DÉBITO' case &CreFrpPgtoTip = TipoDuplicata.CHEQUEP &titulo += 'TIPO CHEQUE PRÓPRIO' case &CreFrpPgtoTip = TipoDuplicata.CHEQUET &titulo += 'TIPO CHEQUE TERCEIROS' case &CreFrpPgtoTip = TipoDuplicata.DINHEIRO &titulo += 'TIPO DINHEIRO' case &CreFrpPgtoTip = TipoDuplicata.DUPLICATA &titulo += 'TIPO DUPLICATA' case &CreFrpPgtoTip = TipoDuplicata.PIX &titulo += 'TIPO PIX' OtherWise &titulo += 'TODOS TIPOS' EndCase
MB 4 MT 2
Header print Cabecalho If &IsSintetico = False If &TCon077_ExibeStatusDebitoCliente <> 'S' Print Menu Else Print Menu2 EndIf Else Print MenuSintetico EndIf End &VetCreCbrCod() = 0 &VetCreCbrNom() = '' &VetCreVlrSdo() = 0 &VetCreVlrJur() = 0 &TotCreVlrSdo = 0 &TotComCreVlrDup = 0 &index = 1 &X =1 //############################################## If &IsSintetico = False // Analítico For Each Order EmpCod,FilCod, CreRecPag,CreCliRaz,CreDupNro when &Ordem = 'R' Order EmpCod,FilCod, CreRecPag,CreCliCod when &Ordem = 'C' Order EmpCod,FilCod, CreRecPag,CreDtaVct when &Ordem = 'D' Order EmpCod,FilCod, CreRecPag,CreCbrCod when &Ordem = 'L' Order EmpCod,FilCod, CreRecPag,CreVenCod when &Ordem = 'V' Where EmpCod = &EmpCod Where FilCod = &FilCod Where CreRecPag = &CreRecPag Where CreFilPgt = &CreFilPgt when not &CreFilPgt.IsEmpty() Where CreFrpPgtoCod = &CreFrpPgtoCod when not &CreFrpPgtoCod.IsEmpty() Where CreFrpPgtoTip <> TipoDuplicata.CARTAOC and CreFrpPgtoTip <> TipoDuplicata.CARTAOD when &CreFrpPgtoCod.IsEmpty() Where CreSts <> Status_Duplicata.CANCELADA Where CreCliCod = &CReCliCod when not &CreCliCod.IsEmpty() Where ((CreDtaVct >= &CreDtaVctIni and CreDtaVct <= &CreDtaVctFin and &IsPromessa = false) or (((CreDtaVct >= &CreDtaVctIni and CreDtaVct <= &CreDtaVctFin) or (CreDtaProPag >= &CreDtaVctIni and CreDtaProPag <= &CreDtaVctFin)) and &IsPromessa = true)) // Where CreVlrSdo > 0 when &Status = 'A' Where CreVlrSdo <> CreVlrDup //when &Status = 'P' Where CreCliCobCidCod = &CidCod when not &CidCod.IsEmpty() Where CreCliCobUfeCod = &UfeCod when not &UfeCod.IsEmpty() Where CreVenAreCod = &AreCod when not &AreCod.IsEmpty() Where CreCbrCod = &CreCbrCod when not &CreCbrCod.IsEmpty() Where CreVenCod = &PesCod When not &PesCod.IsEmpty() Where CreDtaEms >= &CreDtaEmsIni and CreDtaEms <= &CreDtaEmsFin Where CreCliClaTip = &CreCliClaTip when not &CreCliClaTip.IsEmpty() Where ((&CreDupPrt.IsEmpty()) or (&CreDupPrt = 'S' and CreDtaPrt.IsEmpty()) or (&CreDupPrt = 'P' and not CreDtaPrt.IsEmpty() and (CreDtaAdv.IsEmpty() or CreDtaAdv.IsNull())) or (&CreDupPrt = 'C' and not CreDtaCrt.IsEmpty() and (CreDtaAdv.IsEmpty() or CreDtaAdv.IsNull()) and (CreDtaPrt.IsEmpty() or CreDtaPrt.IsNull())) or (&CreDupPrt = 'A' and not CreDtaAdv.IsEmpty())) Where (CreIsPer <> true or CreIsPer.IsNull()) when &IsPerdido = false Where not CrePedCod.IsEmpty() when &IsPedido = True where CreSts <> Status_Duplicata.DESCONTADA when &StsDup = 'EXCETODESCONTADAS' where CreSts = Status_Duplicata.DESCONTADA when &StsDup = 'DESCONTADAS'
Do Case Case (&index = 2 and (&Ordem = 'R' Or &Ordem = 'C')) // se for ordenado por Cliente Nome ou Código If CreCliCod <> &AuxCreCliCod // e o Cliente atual For diferente do anterior imprimi o saldo e do anterior e Zera variavel Print TotalCliente &x = 1 &CliTotCreVlrSdo = 0 EndIf Case &index = 2 and &Ordem = 'V' //Vendedor If CreVenCod <> &AuxCreVenCod Print TotalVendedor &CliTotCreVlrSdo = 0 EndIf Case &index = 2 and &Ordem = 'L' //LOCAL DE COBRANÇA If CreCbrCod <> &AuxCreCbrCod Print TotalLocalCobranca &CliTotCreVlrSdo = 0 EndIf Case &index = 2 and &Ordem = 'D' //Data de Vencimento If CreDtaVct <> &AuxCreDtaVct Print TotalVencimento &CliTotCreVlrSdo = 0 EndIf EndCase &index = 2 &AuxCreCliCod = CreCliCod &AuxCreVenCod = CreVenCod &AuxCreCbrCod = CreCbrCod if &AuxCreCbrCod.IsEmpty() &AuxCreCbrCod = 1 EndiF
&AuxCreCbrNom = CreCbrNom &AuxCreDtaVct = CreDtaVct RetornaPrimeiroTelefone.Call(EmpCod,CreCliCod,&PesFonNum) &CreCliRaz = substr(CreCliCodRaz,1,45) &CreCliCobCidNom = substr(trim(CreCliCobCidNom),1,15)+'/'+CreCliCobUfeCod
//################# CÁLCULO DE JUROS ################################################## &CreVlrSdo = 0
For each Order EmpCod,FilCod,CreCod,CrePagCod where CrePagSts <> Status_Caixa.Cancelado &CreVlrSdo += CrePagVlr Endfor
For each Order EmpCod,FilCod,CreRenCod &CreVlrSdo += CreRenVlr EndFor
//################## Contabiliza Total por Local de Cobrança ########################## &VetCreCbrCod(&AuxCreCbrCod) = &AuxCreCbrCod &VetCreCbrNom(&AuxCreCbrCod) = &AuxCreCbrNom &VetCreVlrSdo(&AuxCreCbrCod) += CreVlrSdo &VetCreVlrJur(&AuxCreCbrCod) += &CreVlrJur //#####################################################################################
&TotCreVlrSdo += &CreVlrSdo
&CliTotCreVlrSdo += &CreVlrSdo &CreDtaPrmPag.SetEmpty() &CreDtaPrmPag = CreDtaPrmPag
//################################ CASE IMPRESSÃO ############################################## Do Case Case (&x = 1 and (&Ordem = 'R' Or &Ordem = 'C')) Print Dados Noskip If &TCon077_ExibeStatusDebitoCliente <> 'S' Print Dados2 Else Print Dados3 EndIf &x = 2 Case (&x = 2 and (&Ordem = 'R' Or &Ordem = 'C')) If &TCon077_ExibeStatusDebitoCliente <> 'S' Print Dados2 Else Print Dados3 EndIf OtherWise
Print Dados Noskip If &TCon077_ExibeStatusDebitoCliente <> 'S' Print Dados2 Else Print Dados3 EndIf EndCase
//################################## IMPRESSÃO DAS OBSERVAÇÕES E COMBRAÇAS ###################### If &IsMostrarObs = true
&Intobs = 1 For Each Order CreCobCod &CreMetNom = '' &CreResNom = '' If &Intobs = 1 Print Observacao &Intobs = 2 EndIf &CreMetNom = substr(CreMetNom,1,40) &CreResNom = substr(CreResNom,1,40) &CreCobObs = SubStr(CreCobObs,1,65) &CreCobObs2 = SubStr(CreCobObs,66,100) Print ObservacaoDesc If not &CreCobObs2.Trim().IsEmpty() Print ObservacaoDesc2 EndIf EndFor Endif
If &IsDetalhaPedido = true // Vai Mostrar o Pedido e os Produtos Daquele Pedido. if not CrePedCod.IsEmpty() &CrePedCod = CrePedCod
Do 'GetPedido' Else &CrePedCod = 0 EndIf EndIf
//################################################################################################ EndFor // ######################################### TOTAIS APOS SAIR DO FOR / SERVE PARA O ULTIMO REGISTRO Do Case Case (&index = 2 and (&Ordem = 'R' Or &Ordem = 'C')) Print TotalCliente &CliTotCreVlrSdo = 0 Case &index = 2 and &Ordem = 'V' //Vendedor Print TotalVendedor &CliTotCreVlrSdo = 0 Case &index = 2 and &Ordem = 'L' //LOCAL DE COBRANÇA Print TotalLocalCobranca &CliTotCreVlrSdo = 0 Case &index = 2 and &Ordem = 'D' //Data de Vencimento Print TotalVencimento &CliTotCreVlrSdo = 0 EndCase
//############################################## TOTAL GERAL ############################## If &TCon077_ExibeStatusDebitoCliente = 'S' Print totalComissao EndIf Print TotalGeral Else For Each Order EmpCod,FilCod, CreRecPag,CreCliRaz,CreDupNro when &Ordem = 'R' Order EmpCod,FilCod, CreRecPag,CreCliCod when &Ordem = 'C' Order EmpCod,FilCod, CreRecPag,CreDtaVct when &Ordem = 'D' Order EmpCod,FilCod, CreRecPag,CreCbrCod when &Ordem = 'L' Order EmpCod,FilCod, CreRecPag,CreVenCod when &Ordem = 'V' Where EmpCod = &EmpCod Where FilCod = &FilCod Where CreRecPag = &CreRecPag Where CreSts <> Status_Duplicata.CANCELADA Where CreFilPgt = &CreFilPgt when not &CreFilPgt.IsEmpty() Where CreCliCod = &CReCliCod when not &CreCliCod.IsEmpty() Where ((CreDtaVct >= &CreDtaVctIni and CreDtaVct <= &CreDtaVctFin and &IsPromessa = false) or (((CreDtaVct >= &CreDtaVctIni and CreDtaVct <= &CreDtaVctFin) or (CreDtaProPag >= &CreDtaVctIni and CreDtaProPag <= &CreDtaVctFin)) and &IsPromessa = true)) Where CreVlrSdo > 0 Where CreCliCobCidCod = &CidCod when not &CidCod.IsEmpty() Where CreCliCobUfeCod = &UfeCod when not &UfeCod.IsEmpty() Where CreVenAreCod = &AreCod when not &AreCod.IsEmpty() Where CreCbrCod = &CreCbrCod when not &CreCbrCod.IsEmpty() Where CreVenCod = &PesCod When not &PesCod.IsEmpty() Where CreDtaEms >= &CreDtaEmsIni and CreDtaEms <= &CreDtaEmsFin Where CreCliClaTip = &CreCliClaTip when not &CreCliClaTip.IsEmpty() Where ((&CreDupPrt.IsEmpty()) or (&CreDupPrt = 'S' and CreDtaPrt.IsEmpty()) or (&CreDupPrt = 'P' and not CreDtaPrt.IsEmpty())) Where (CreIsPer <> true or CreIsPer.IsNull()) when &IsPerdido = false Where not CrePedCod.IsEmpty() when &IsPedido = True
Do Case Case (&index = 2 and (&Ordem = 'R' Or &Ordem = 'C')) // se for ordenado por Cliente Nome ou Código If CreCliCod <> &AuxCreCliCod // e o Cliente atual For diferente do anterior imprimi o saldo e do anterior e Zera variavel Print ClienteSintetico Noskip Print SaldoSintetico &CliTotCreVlrSdo = 0 EndIf EndCase &index = 2 &AuxCreCliCod = CreCliCod &AuxCreVenCod = CreVenCod &AuxCreCbrCod = CreCbrCod if &AuxCreCbrCod.IsEmpty() &AuxCreCbrCod = 1 EndiF &AuxCreCbrNom = CreCbrNom &AuxCreDtaVct = CreDtaVct RetornaPrimeiroTelefone.Call(EmpCod,CreCliCod,&PesFonNum) &CreCliRaz = substr(CreCliCodRaz,1,45) &CreCliCobCidNom = substr(trim(CreCliCobCidNom),1,15)+'/'+CreCliCobUfeCod
//################# CÁLCULO DE JUROS ################################################## &CreVlrSdo = 0 For each Order EmpCod,FilCod,CreCod,CrePagCod where CrePagSts <> Status_Caixa.Cancelado &CreVlrSdo += CrePagVlr Endfor
For each Order EmpCod,FilCod,CreRenCod &CreVlrSdo += CreRenVlr EndFor
// &CreVlrSdo = CreVlrTotPgto // If &IsJuros = True // CalculaJuros.Call(EmpCod,CreCbrJurCod,CreDtaVct,ServerDate(), CreVlrSdo,&CreVlrJur, CreCbrMltVlr, &MultaMOeda) // &CreVlrJur += &MultaMOeda // &CreVlrSdo+= &CreVlrJur // EndIf // //##################################################################################### // //################## Contabiliza Total por Local de Cobrança ########################## &VetCreCbrCod(&AuxCreCbrCod) = &AuxCreCbrCod &VetCreCbrNom(&AuxCreCbrCod) = &AuxCreCbrNom &VetCreVlrSdo(&AuxCreCbrCod) += CreVlrSdo &VetCreVlrJur(&AuxCreCbrCod) += &CreVlrJur //#####################################################################################
&TotCreVlrSdo += &CreVlrSdo &CliTotCreVlrSdo += &CreVlrSdo &CreVlrSdo = &CliTotCreVlrSdo EndFor // ######################################### TOTAIS APOS SAIR DO FOR / SERVE PARA O ULTIMO REGISTRO Do Case Case (&index = 2 and (&Ordem = 'R' Or &Ordem = 'C')) Print ClienteSintetico Noskip Print SaldoSintetico &CreVlrSdo = 0 &CliTotCreVlrSdo = 0 EndCase
//############################################## TOTAL GERAL ############################## If &TCon077_ExibeStatusDebitoCliente = 'S' Print totalComissao EndIf Print TotalGeral EndIf
//################################################ Total por Local de Cobrança ####### print CobrancaMenu &Var = 1 Do while &Var <= rows(&VetCreCbrCod()) if &VetCreCbrCod(&Var) <> nullvalue(&VetCreCbrCod(&Var))
&LayCreCbrCod = &VetCreCbrCod(&Var) &LayCreCbrNom = &VetCreCbrNom(&Var) &LayCreVlrSdo = &VetCreVlrSdo(&Var) &LayCreVlrJur = &VetCreVlrJur(&Var) print CobrancaDetalhe endif &Var += 1 EndDo
Footer print Rodape End Sub 'GetPedido' For Each Order EmpCod,FilCod,PedCod Where EmpCod = &EmpCod Where FilCod = &FilCod Where PedCod = &CrePedCod Print DetPedido
For each Order PedItmCod &ProCod = ProCod &ProNom = ProNom &PedQtd = PedQtd &PedVlrUnt = PedVlrUnt &PedVlritmComDsc = PedVlrItmComDsc Print DetPedidoProduto EndFor Print PedLin Exit EndFor EndSub
